Context('Numeric');
do {
  $a = random(1,10,1);
  $b = random(-10,-1,1);
  $c = random(1,10,1);
  $exponent = $a + $b - $c;
} until ($exponent > 5);
$multians = MultiAnswer($a, $b, $c)->with(
singleResult => 1,
    checker => sub {
    my ( $correct, $student, $self ) = @_;
    my ( $astu, $bstu, $cstu ) = @{$student};
    my ( $acor, $bcor, $ccor ) = @{$correct};
    if ( $astu <= 0) {Value::Error('Your value for a should be positive.')};
    if ( $bstu <= 0) {Value::Error('Your value for b should be positive.')};
    if ( $cstu >= 0) {Value::Error('Your value for c should be negative.')};
    if ($astu+$bstu-$cstu != $exponent) {return 0;} else {return 1};
  }
);
 do {
  $d = random(1,10,1);
  $e = random(-10,-1,1);
  $f = random(1,10,1);
  $negexponent = $d + $e - $f;
} until ($negexponent < -5);
$abs = abs($negexponent);
$answer = Compute("none");

